import Vue from 'vue'
import VueRouter from 'vue-router'
import HomeView from '../views/HomeView.vue'
import Error404 from '../views/other/404.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'home',
    component: HomeView,
    meta:{titls:'首页', icon:''}
  },
  {
    path: '/blogArtices',
    name: 'blog',
    meta: {title: '编程技术',icon:'fa-home'},
    component: () => import(/* webpackChunkName: "about" */ '../views/function/BlogPage.vue')
  },
  {
    path: '/techArtices',
    name: 'tech',
    meta: {title: '科技前沿',icon:'fa-home'},
    //component: () => import(/* webpackChunkName: "about" */'')
  },
  {
    path: '/resourceList',
    name: 'resource',
    meta: {title: '福利资源',icon:'fa-home'},
    //component: () => import(/* webpackChunkName: "about" */'')
  },
  {
    path: '/leaveMessage',
    name: 'message',
    meta: {title: '留言给我',icon:'fa-home'},
    //component: () => import(/* webpackChunkName: "about" */'')
  },
  {
    path: '/lifeArticles',
    name: 'myLife',
    meta: {title: '生活随笔',icon:'fa-home'},
    //component: () => import(/* webpackChunkName: "about" */'')
  },
  {
    path: '/about',
    name: 'about',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/AboutView.vue'),
    meta:{titls:'关于',icon: ''}
  },
  {
    name: 'error',
    path: '/error',
    component: Error404
  }
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

export default router
